import Foundation
import Security

actor KeychainManager {

    static let shared = KeychainManager()

    private let bundleID: String
    private let appGroupID: String?

    private init(appGroupID: String? = nil) {
        self.bundleID = Bundle.main.bundleIdentifier ?? "com.vreader.app"
        self.appGroupID = appGroupID
        performFirstLaunchCleanupIfNeeded()
    }

    private func performFirstLaunchCleanupIfNeeded() {
        let sentinelKey = "keychainDidInitialize"
        guard !UserDefaults.standard.bool(forKey: sentinelKey) else { return }
        performDeleteAll()
        UserDefaults.standard.set(true, forKey: sentinelKey)
    }

    // MARK: - Save String

    func save(key: KeychainKey, value: String) throws {
        guard let data = value.data(using: .utf8) else {
            throw AppError.authentication(status: errSecParam)
        }
        try save(key: key, data: data)
    }

    // MARK: - Load String

    func load(key: KeychainKey) -> String? {
        guard let data: Data = load(key: key) else { return nil }
        return String(data: data, encoding: .utf8)
    }

    // MARK: - Save Data

    func save(key: KeychainKey, data: Data) throws {
        var query = baseQuery(for: key)
        query[kSecValueData as String] = data

        let addStatus = SecItemAdd(query as CFDictionary, nil)

        if addStatus == errSecSuccess {
            return
        }

        if addStatus == errSecDuplicateItem {
            let searchQuery = baseQuery(for: key)
            let updateAttributes: [String: Any] = [
                kSecValueData as String: data
            ]
            let updateStatus = SecItemUpdate(searchQuery as CFDictionary, updateAttributes as CFDictionary)
            guard updateStatus == errSecSuccess else {
                DiagnosticsService.shared.log(
                    level: .error,
                    message: "Keychain update failed for key: \(key.logName), status: \(updateStatus)"
                )
                throw AppError.authentication(status: updateStatus)
            }
            return
        }

        DiagnosticsService.shared.log(
            level: .error,
            message: "Keychain add failed for key: \(key.logName), status: \(addStatus)"
        )
        throw AppError.authentication(status: addStatus)
    }

    // MARK: - Load Data

    func load(key: KeychainKey) -> Data? {
        var query = baseQuery(for: key)
        query[kSecReturnData as String] = true
        query[kSecMatchLimit as String] = kSecMatchLimitOne

        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)

        if status == errSecItemNotFound {
            return nil
        }

        guard status == errSecSuccess else {
            DiagnosticsService.shared.log(
                level: .error,
                message: "Keychain load failed for key: \(key.logName), status: \(status)"
            )
            return nil
        }

        return result as? Data
    }

    // MARK: - Delete

    func delete(key: KeychainKey) throws {
        let query = baseQuery(for: key)
        let status = SecItemDelete(query as CFDictionary)

        guard status == errSecSuccess || status == errSecItemNotFound else {
            DiagnosticsService.shared.log(
                level: .error,
                message: "Keychain delete failed for key: \(key.logName), status: \(status)"
            )
            throw AppError.authentication(status: status)
        }
    }

    // MARK: - Exists

    func exists(key: KeychainKey) -> Bool {
        var query = baseQuery(for: key)
        query[kSecReturnData as String] = false
        query[kSecMatchLimit as String] = kSecMatchLimitOne

        let status = SecItemCopyMatching(query as CFDictionary, nil)
        return status == errSecSuccess
    }

    // MARK: - Delete All

    func deleteAll() {
        performDeleteAll()
    }

    // MARK: - Private Helpers

    private func performDeleteAll() {
        let services = [
            bundleID,
            bundleID + ".webdav",
            bundleID + ".smb"
        ]

        for service in services {
            let query: [String: Any] = [
                kSecClass as String: kSecClassGenericPassword,
                kSecAttrService as String: service,
                kSecAttrSynchronizable as String: kSecAttrSynchronizableAny
            ]
            let status = SecItemDelete(query as CFDictionary)
            if status != errSecSuccess && status != errSecItemNotFound {
                DiagnosticsService.shared.log(
                    level: .warning,
                    message: "Keychain deleteAll partial failure for service: \(service), status: \(status)"
                )
            }
        }
    }

    private func baseQuery(for key: KeychainKey) -> [String: Any] {
        var query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: key.service(bundleID: bundleID),
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlock,
            kSecAttrSynchronizable as String: key.isSynchronizable ? kCFBooleanTrue! : kCFBooleanFalse!
        ]

        if let account = key.account {
            query[kSecAttrAccount as String] = account
        } else {
            query[kSecAttrAccount as String] = key.logName
        }

        if let groupID = appGroupID {
            query[kSecAttrAccessGroup as String] = groupID
        }

        return query
    }
}

// MARK: - KeychainKey

enum KeychainKey {
    case geminiAPIKey
    case googleDriveAccessToken
    case googleDriveRefreshToken
    case dropboxAccessToken
    case dropboxRefreshToken
    case oneDriveAccessToken
    case oneDriveRefreshToken
    case webDAVPassword(host: String)
    case smbPassword(host: String)

    var isSynchronizable: Bool {
        switch self {
        case .googleDriveAccessToken,
             .googleDriveRefreshToken,
             .dropboxAccessToken,
             .dropboxRefreshToken,
             .oneDriveAccessToken,
             .oneDriveRefreshToken:
            return true
        case .geminiAPIKey,
             .webDAVPassword,
             .smbPassword:
            return false
        }
    }

    func service(bundleID: String) -> String {
        switch self {
        case .webDAVPassword:
            return bundleID + ".webdav"
        case .smbPassword:
            return bundleID + ".smb"
        default:
            return bundleID
        }
    }

    var account: String? {
        switch self {
        case .webDAVPassword(let host):
            return host
        case .smbPassword(let host):
            return host
        default:
            return nil
        }
    }

    var logName: String {
        switch self {
        case .geminiAPIKey:
            return "geminiAPIKey"
        case .googleDriveAccessToken:
            return "googleDriveAccessToken"
        case .googleDriveRefreshToken:
            return "googleDriveRefreshToken"
        case .dropboxAccessToken:
            return "dropboxAccessToken"
        case .dropboxRefreshToken:
            return "dropboxRefreshToken"
        case .oneDriveAccessToken:
            return "oneDriveAccessToken"
        case .oneDriveRefreshToken:
            return "oneDriveRefreshToken"
        case .webDAVPassword(let host):
            return "webDAVPassword(host:\(host))"
        case .smbPassword(let host):
            return "smbPassword(host:\(host))"
        }
    }
}
