import XCTest
@testable import Vreader

final class KeychainManagerTests: XCTestCase {

    private var manager: KeychainManager!

    override func setUp() async throws {
        try await super.setUp()
        manager = KeychainManager.shared
        await manager.deleteAll()
    }

    override func tearDown() async throws {
        await manager.deleteAll()
        try await super.tearDown()
    }

    // MARK: - Basic String CRUD

    func testSaveAndLoadString() async throws {
        let key = KeychainKey.geminiAPIKey
        let value = "test-api-key-12345"

        try await manager.save(key: key, value: value)
        let loaded: String? = await manager.load(key: key)

        XCTAssertEqual(loaded, value)
    }

    func testLoadMissingKeyReturnsNil() async {
        let key = KeychainKey.geminiAPIKey
        let loaded: String? = await manager.load(key: key)
        XCTAssertNil(loaded)
    }

    func testDeleteRemovesKey() async throws {
        let key = KeychainKey.geminiAPIKey
        let value = "to-be-deleted"

        try await manager.save(key: key, value: value)
        try await manager.delete(key: key)
        let loaded: String? = await manager.load(key: key)

        XCTAssertNil(loaded)
    }

    func testSaveLoadDeleteCycle() async throws {
        let key = KeychainKey.googleDriveAccessToken
        let value = "access-token-abc"

        try await manager.save(key: key, value: value)
        let loaded: String? = await manager.load(key: key)
        XCTAssertEqual(loaded, value)

        try await manager.delete(key: key)
        let afterDelete: String? = await manager.load(key: key)
        XCTAssertNil(afterDelete)
    }

    // MARK: - Upsert Semantics

    func testSaveTwiceSameKeyDoesNotThrow() async throws {
        let key = KeychainKey.geminiAPIKey
        let firstValue = "first-value"
        let secondValue = "second-value"

        try await manager.save(key: key, value: firstValue)
        try await manager.save(key: key, value: secondValue)

        let loaded: String? = await manager.load(key: key)
        XCTAssertEqual(loaded, secondValue, "Second save should overwrite first")
    }

    func testUpsertDoesNotThrowErrSecDuplicateItem() async {
        let key = KeychainKey.dropboxAccessToken

        do {
            try await manager.save(key: key, value: "v1")
            try await manager.save(key: key, value: "v2")
            try await manager.save(key: key, value: "v3")
        } catch {
            XCTFail("Upsert should not throw, but threw: \(error)")
        }
    }

    // MARK: - Data CRUD

    func testSaveAndLoadData() async throws {
        let key = KeychainKey.dropboxRefreshToken
        let data = Data([0x01, 0x02, 0x03, 0xFF])

        try await manager.save(key: key, data: data)
        let loaded: Data? = await manager.load(key: key)

        XCTAssertEqual(loaded, data)
    }

    func testLoadMissingDataKeyReturnsNil() async {
        let key = KeychainKey.oneDriveRefreshToken
        let loaded: Data? = await manager.load(key: key)
        XCTAssertNil(loaded)
    }

    // MARK: - Exists

    func testExistsReturnsFalseForMissingKey() async {
        let exists = await manager.exists(key: .geminiAPIKey)
        XCTAssertFalse(exists)
    }

    func testExistsReturnsTrueAfterSave() async throws {
        let key = KeychainKey.geminiAPIKey
        try await manager.save(key: key, value: "some-value")
        let exists = await manager.exists(key: key)
        XCTAssertTrue(exists)
    }

    func testExistsReturnsFalseAfterDelete() async throws {
        let key = KeychainKey.geminiAPIKey
        try await manager.save(key: key, value: "some-value")
        try await manager.delete(key: key)
        let exists = await manager.exists(key: key)
        XCTAssertFalse(exists)
    }

    // MARK: - Host-Scoped Keys (WebDAV / SMB)

    func testWebDAVPasswordsStoredIndependentlyPerHost() async throws {
        let hostA = "a.example.com"
        let hostB = "b.example.com"
        let passwordA = "password-for-a"
        let passwordB = "password-for-b"

        try await manager.save(key: .webDAVPassword(host: hostA), value: passwordA)
        try await manager.save(key: .webDAVPassword(host: hostB), value: passwordB)

        let loadedA: String? = await manager.load(key: .webDAVPassword(host: hostA))
        let loadedB: String? = await manager.load(key: .webDAVPassword(host: hostB))

        XCTAssertEqual(loadedA, passwordA, "Host A password should be independent")
        XCTAssertEqual(loadedB, passwordB, "Host B password should be independent")
        XCTAssertNotEqual(loadedA, loadedB, "Passwords must not collide")
    }

    func testSMBPasswordsStoredIndependentlyPerHost() async throws {
        let hostA = "nas.local"
        let hostB = "server.local"

        try await manager.save(key: .smbPassword(host: hostA), value: "smb-pass-a")
        try await manager.save(key: .smbPassword(host: hostB), value: "smb-pass-b")

        let loadedA: String? = await manager.load(key: .smbPassword(host: hostA))
        let loadedB: String? = await manager.load(key: .smbPassword(host: hostB))

        XCTAssertEqual(loadedA, "smb-pass-a")
        XCTAssertEqual(loadedB, "smb-pass-b")
    }

    func testWebDAVAndSMBSameHostDoNotCollide() async throws {
        let host = "shared.example.com"

        try await manager.save(key: .webDAVPassword(host: host), value: "webdav-pass")
        try await manager.save(key: .smbPassword(host: host), value: "smb-pass")

        let webdav: String? = await manager.load(key: .webDAVPassword(host: host))
        let smb: String? = await manager.load(key: .smbPassword(host: host))

        XCTAssertEqual(webdav, "webdav-pass")
        XCTAssertEqual(smb, "smb-pass")
        XCTAssertNotEqual(webdav, smb)
    }

    // MARK: - isSynchronizable

    func testOAuthTokensAreSynchronizable() {
        XCTAssertTrue(KeychainKey.googleDriveAccessToken.isSynchronizable)
        XCTAssertTrue(KeychainKey.googleDriveRefreshToken.isSynchronizable)
        XCTAssertTrue(KeychainKey.dropboxAccessToken.isSynchronizable)
        XCTAssertTrue(KeychainKey.dropboxRefreshToken.isSynchronizable)
        XCTAssertTrue(KeychainKey.oneDriveAccessToken.isSynchronizable)
        XCTAssertTrue(KeychainKey.oneDriveRefreshToken.isSynchronizable)
    }

    func testNonOAuthKeysAreNotSynchronizable() {
        XCTAssertFalse(KeychainKey.geminiAPIKey.isSynchronizable)
        XCTAssertFalse(KeychainKey.webDAVPassword(host: "example.com").isSynchronizable)
        XCTAssertFalse(KeychainKey.smbPassword(host: "nas.local").isSynchronizable)
    }

    // MARK: - First-Launch Cleanup (Reinstall Simulation)

    func testReinstallSimulationWipesExistingItems() async throws {
        let key = KeychainKey.geminiAPIKey
        try await manager.save(key: key, value: "stale-api-key")

        let existsBefore = await manager.exists(key: key)
        XCTAssertTrue(existsBefore, "Item should exist before simulated reinstall")

        UserDefaults.standard.removeObject(forKey: "keychainDidInitialize")

        await manager.deleteAll()

        let existsAfter = await manager.exists(key: key)
        XCTAssertFalse(existsAfter, "Item should be wiped after deleteAll (simulating reinstall cleanup)")
    }

    func testSentinelFlagPreventsDoubleCleanup() async throws {
        let key = KeychainKey.geminiAPIKey
        try await manager.save(key: key, value: "persistent-key")

        UserDefaults.standard.set(true, forKey: "keychainDidInitialize")

        let exists = await manager.exists(key: key)
        XCTAssertTrue(exists, "Item should persist when sentinel is already set")
    }

    // MARK: - Delete Non-Existent Key

    func testDeleteNonExistentKeyDoesNotThrow() async {
        do {
            try await manager.delete(key: .geminiAPIKey)
        } catch {
            XCTFail("Deleting a non-existent key should not throw, but threw: \(error)")
        }
    }

    // MARK: - DeleteAll

    func testDeleteAllRemovesAllItems() async throws {
        try await manager.save(key: .geminiAPIKey, value: "key1")
        try await manager.save(key: .googleDriveAccessToken, value: "key2")
        try await manager.save(key: .webDAVPassword(host: "host.com"), value: "key3")
        try await manager.save(key: .smbPassword(host: "nas.local"), value: "key4")

        await manager.deleteAll()

        let e1 = await manager.exists(key: .geminiAPIKey)
        let e2 = await manager.exists(key: .googleDriveAccessToken)
        let e3 = await manager.exists(key: .webDAVPassword(host: "host.com"))
